import React from 'react'
import TicketCard from './TicketCard'

function StatusColumn({ title, content }) {
    console.log('>>>>', content)
    return <div className='border rounded-md border-gray-600 h-full bg-gray-300'>
        <div className='ahqt ahri ahrt ahsb ahsp ahsv ahtd ahtf ahtj ahud ahuk'>
            {title}
        </div>
        <div>
            {content}
        </div>
    </div>
}

function groupBy(arr, key) {
    const dict = new Map()
    arr.forEach((item) => {
        dict.set(item[key], [...(dict.get(item[key]) || []), item])
    })
    return dict
}
export default function StatusColumns({ cards }) {
    const columns = groupBy(cards, 'ticketStatus')
    const titleComponent = (columnName) => <span>{columnName}</span>
    const contentComponent = (columnTickets) => columnTickets.map((tkt) => <TicketCard id={tkt.id} title={tkt.title} storyPoints={tkt.storyPoints} profilePicUrl={tkt.assignee.avatar} type={'STORY'} />)
    return columns.keys().map((columnName) => <StatusColumn title={titleComponent(columnName)} content={() => contentComponent(columns[columnName])} />)
}
